9	export function quote(input: any): unknown {
10	  const itemsBase = input.items.reduce(
11	    (sum: number, item: any) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
12	    0
13	  );
14	  return { premium: itemsBase + PROCESSING_FEE };
15	}
